public boolean equals(Object o)
    {
        if (o == this) return true;
        if (o == null) return false;
        // 13-Nov-2012, tatu: by default, require strict type equality.
        //   Re-evaluate if this becomes an issue.
        if (o.getClass() != getClass()) return false;
        // 13-Nov-2012, tatu: Should we have specific rules on matching USE_DEFAULT?
        //   (like, it only ever matching exact instance)
        //   If we did, would need to check symmetrically; that is, if either 'this'
        //   or 'o' was USE_DEFAULT, both would have to be.
        PropertyName other = (PropertyName) o;
        if (_simpleName == null) {
            if (other._simpleName != null) return false;
        } else if (!_simpleName.equals(other._simpleName)) {
            return false;
        }
        if (_namespace == null) {
            return (null == other._namespace);
        }
        return _namespace.equals(other._namespace);
    }

    @Override
    public int hashCode() {
        return Objects.hashCode(_simpleName) * 31
                + Objects.hashCode(_namespace);
    }

    @Override
    public String toString() {
        if (_namespace == null) {
            return _simpleName;
        }
        return "{"+_namespace + "}" + _simpleName;
    }

private static short[] newSizeClass(int index, int log2Group, int log2Delta, int nDelta, int pageShifts) {
    short isMultiPageSize;
    if (log2Delta >= pageShifts) {
        isMultiPageSize = yes;
    } else {
        int pageSize = 1 << pageShifts;
        int size = calculateSize(log2Group, nDelta, log2Delta);

        isMultiPageSize = size == size / pageSize * pageSize? yes : no;
    }

    int log2Ndelta = nDelta == 0? 0 : log2(nDelta);

    byte remove = 1 << log2Ndelta < nDelta? yes : no;

    int log2Size = log2Delta + log2Ndelta == log2Group? log2Group + 1 : log2Group;
    if (log2Size == log2Group) {
        remove = yes;
    }

    short isSubpage = log2Size < pageShifts + LOG2_SIZE_CLASS_GROUP? yes : no;

    int log2DeltaLookup = log2Size < LOG2_MAX_LOOKUP_SIZE ||
                          log2Size == LOG2_MAX_LOOKUP_SIZE && remove == no
            ? log2Delta : no;

    return new short[] {
            (short) index, (short) log2Group, (short) log2Delta,
            (short) nDelta, isMultiPageSize, isSubpage, (short) log2DeltaLookup
    };
}

public void toString(StringBuilder buf) {
    if (Modifier.isPublic(modifiers)) {
        buf.append("\tpublic ");
    }

    if ("<init>".equals(name)) {
        buf.append(classWriter.name);
    } else {
        buf.append(getTypeName(returnType)).append(' ').append(name);
    }

    boolean newLine = paramTypes.length > 3;
    buf.append('(');
    if (newLine) {
        buf.append("\n\t\t\t");
    }

    for (int i = 0; i < paramTypes.length; i++) {
        if (i != 0) {
            if (newLine) {
                buf.append(",\n\t\t\t");
            } else {
                buf.append(", ");
            }
        }
        Class paramType = paramTypes[i];
        String paramName = paramNames[i];
        buf.append(getTypeName(paramType)).append(' ').append(paramName);
    }

    if (newLine) {
        buf.append("\n\t");
    }

    buf.append(") {\n");

    for (int i = 0; i < statements.size(); i++) {
        if (i != 0) {
            buf.append('\n');
        }
        Statement stmt = statements.get(i);
        stmt.toString(this, buf, 2);
    }

    buf.append("\n\t}");
}

final void setInputFrameFromDescriptor(
        final SymbolTable symbolTable,
        final int access,
        final String descriptor,
        final int maxLocals) {
    inputLocals = new int[maxLocals];
    inputStack = new int[0];
    int inputLocalIndex = 0;
    if ((access & Opcodes.ACC_STATIC) == 0) {
        if ((access & Constants.ACC_CONSTRUCTOR) == 0) {
            inputLocals[inputLocalIndex++] =
                    REFERENCE_KIND | symbolTable.addType(symbolTable.className);
        } else {
            inputLocals[inputLocalIndex++] = UNINITIALIZED_THIS;
        }
    }
    for (Type argumentType : Type.getArgumentTypes(descriptor)) {
        int abstractType =
                getAbstractTypeFromDescriptor(symbolTable, argumentType.getDescriptor(), 0);
        inputLocals[inputLocalIndex++] = abstractType;
        if (abstractType == LONG || abstractType == DOUBLE) {
            inputLocals[inputLocalIndex++] = TOP;
        }
    }
    while (inputLocalIndex < maxLocals) {
        inputLocals[inputLocalIndex++] = TOP;
    }
}

public void visitVarInsn(final int opcode, final int var) {
    lastBytecodeOffset = code.length;
    // Add the instruction to the bytecode of the method.
    if (var < 4 && opcode != Opcodes.RET) {
        int optimizedOpcode;
        if (opcode < Opcodes.ISTORE) {
            optimizedOpcode = Constants.ILOAD_0 + ((opcode - Opcodes.ILOAD) << 2) + var;
        } else {
            optimizedOpcode = Constants.ISTORE_0 + ((opcode - Opcodes.ISTORE) << 2) + var;
        }
        code.putByte(optimizedOpcode);
    } else if (var >= 256) {
        code.putByte(Constants.WIDE).put12(opcode, var);
    } else {
        code.put11(opcode, var);
    }
    // If needed, update the maximum stack size and number of locals, and stack map frames.
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(opcode, var, null, null);
    }

    int currentMaxLocals;
    if (opcode == Opcodes.LLOAD
            || opcode == Opcodes.DLOAD
            || opcode == Opcodes.LSTORE
            || opcode == Opcodes.DSTORE) {
        currentMaxLocals = var + 2;
    } else {
        currentMaxLocals = var + 1;
    }
    if (currentMaxLocals > maxLocals) {
        maxLocals = currentMaxLocals;
    }
}

public String getClassName() {
    switch (sort) {
        case VOID:
            return "void";
        case BOOLEAN:
            return "boolean";
        case CHAR:
            return "char";
        case BYTE:
            return "byte";
        case SHORT:
            return "short";
        case INT:
            return "int";
        case FLOAT:
            return "float";
        case LONG:
            return "long";
        case DOUBLE:
            return "double";
        case ARRAY:
            Type elementType = getTypeInternal(valueBuffer, valueBegin + getDimensions(), valueEnd);
            StringBuilder stringBuilder = new StringBuilder(elementType.getClassName());
            for (int i = getDimensions(); i > 0; --i) {
                stringBuilder.append("[]");
            }
            return stringBuilder.toString();
        case OBJECT:
        case INTERNAL:
            return valueBuffer.substring(valueBegin, valueEnd).replace('/', '.');
        default:
            throw new AssertionError();
    }
}

static <T> List<T> parseArray(String text, Type[] types, JSONReader.Feature... features) {
    if (text == null || text.isEmpty()) {
        return null;
    }

    final JSONReader.Context context = JSONFactory.createReadContext(features);
    try (JSONReader reader = JSONReader.of(text, context)) {
        if (reader.nextIfNull()) {
            return null;
        }

        reader.startArray();
        List<T> array = new ArrayList<>(types.length);
        for (int i = 0; i < types.length; i++) {
            array.add(
                    reader.read(types[i])
            );
        }
        reader.endArray();
        if (reader.resolveTasks != null) {
            reader.handleResolveTasks(array);
        }
        if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
            throw new JSONException(reader.info("input not end"));
        }
        return array;
    }
}

static <T> T parseObject(byte[] jsonbBytes, Class<T> objectClass, JSONReader.Context context) {
    try (JSONReaderJSONB jsonReader = new JSONReaderJSONB(
            context,
            jsonbBytes,
            0,
            jsonbBytes.length)
    ) {
        Object object;
        if (objectClass == Object.class) {
            object = jsonReader.readAnyObject();
        } else {
            ObjectReader objectReader = context.provider.getObjectReader(
                    objectClass,
                    (context.features & JSONReader.Feature.FieldBased.mask) != 0
            );
            if ((context.features & JSONReader.Feature.SupportArrayToBean.mask) != 0
                    && jsonReader.isArray()
                    && objectReader instanceof ObjectReaderBean
            ) {
                object = objectReader.readArrayMappingJSONBObject(jsonReader, objectClass, null, 0);
            } else {
                object = objectReader.readJSONBObject(jsonReader, objectClass, null, 0);
            }
        }

        if (jsonReader.resolveTasks != null) {
            jsonReader.handleResolveTasks(object);
        }
        return (T) object;
    }
}

static int writeTypeName(byte[] bytes, int off, String typeName, JSONWriter jsonWriter) {
    JSONWriterJSONB jsonWriterJSONB = (JSONWriterJSONB) jsonWriter;
    SymbolTable symbolTable = jsonWriter.symbolTable;
    bytes[off++] = BC_TYPED_ANY;

    long hash = Fnv.hashCode64(typeName);

    int symbol = -1;
    if (symbolTable != null) {
        symbol = symbolTable.getOrdinalByHashCode(hash);
        if (symbol == -1 && jsonWriterJSONB.symbols != null) {
            symbol = jsonWriterJSONB.symbols.get(hash);
        }
    } else if (jsonWriterJSONB.symbols != null) {
        symbol = jsonWriterJSONB.symbols.get(hash);
    }

    if (symbol == -1) {
        if (jsonWriterJSONB.symbols == null) {
            jsonWriterJSONB.symbols = new TLongIntHashMap();
        }
        jsonWriterJSONB.symbols.put(hash, symbol = jsonWriterJSONB.symbolIndex++);
    } else {
        return JSONB.IO.writeInt32(bytes, off, symbol);
    }

    off = writeString(bytes, off, typeName);
    return writeInt32(bytes, off, symbol);
}

@Override
        public void set(JSONPath.Context context, Object value) {
            Object object = context.parent == null
                    ? context.root
                    : context.parent.value;

            if (object instanceof List) {
                List list = (List) object;
                for (int i = 0, size = list.size(); i < size; i++) {
                    int index = begin >= 0 ? i : i - size;
                    if (index >= begin && index < end) {
                        list.set(i, value);
                    }
                }
                return;
            }

            if (object != null) {
                Class objectClass = object.getClass();
                if (objectClass.isArray()) {
                    int size = Array.getLength(object);
                    for (int i = 0; i < size; i++) {
                        int index = begin >= 0 ? i : i - size;
                        if (index >= begin && index < end) {
                            Array.set(object, i, value);
                        }
                    }
                    return;
                }
            }

            throw new JSONException("UnsupportedOperation " + getClass());
        }

@Override
    public Object extract(JSONReader jsonReader) {
        if (jsonReader.jsonb) {
            if (jsonReader.isObject()) {
                jsonReader.nextIfObjectStart();
                while (!jsonReader.nextIfObjectEnd()) {
                    long nameHashCode = jsonReader.readFieldNameHashCode();
                    if (nameHashCode == 0) {
                        continue;
                    }

                    boolean match = nameHashCode == this.nameHashCode;
                    if (!match && (!jsonReader.isObject()) && !jsonReader.isArray()) {
                        jsonReader.skipValue();
                        continue;
                    }

                    return jsonReader.readInt32();
                }
            }
        } else if (jsonReader.nextIfObjectStart()) {
            while (!jsonReader.nextIfObjectEnd()) {
                long nameHashCode = jsonReader.readFieldNameHashCode();
                boolean match = nameHashCode == this.nameHashCode;

                if (!match) {
                    jsonReader.skipValue();
                    continue;
                }

                return jsonReader.readInt32();
            }
        }

        return null;
    }

