@Override
    public Object extract(JSONReader jsonReader) {
        if (jsonReader == null) {
            return null;
        }

        if (!extractSupport) {
            Object root = jsonReader.readAny();
            return eval(root);
        }

        Context context0 = new Context(this, null, first, second, 0);
        first.accept(jsonReader, context0);

        Context context1 = new Context(this, context0, second, null, 0);

        if (context0.eval) {
            second.eval(context1);
        } else {
            second.accept(jsonReader, context1);
        }

        Object contextValue = context1.value;

        if ((features & Feature.AlwaysReturnList.mask) != 0) {
            if (contextValue == null) {
                contextValue = new JSONArray();
            } else if (!(contextValue instanceof List)) {
                contextValue = JSONArray.of(contextValue);
            }
        }

        if (contextValue instanceof Sequence) {
            contextValue = ((Sequence) contextValue).values;
        }

        return contextValue;
    }

JSONPathTypedMultiIndexes(
        JSONPath[] paths,
        JSONPath prefix,
        JSONPath[] indexPaths,
        Type[] types,
        String[] formats,
        long[] pathFeatures,
        ZoneId zoneId,
        long features
) {
    super(paths, types, formats, pathFeatures, zoneId, features);
    this.prefix = prefix;
    this.indexPaths = indexPaths;
    int[] indexes = new int[paths.length];
    for (int i = 0; i < indexPaths.length; i++) {
        JSONPathSingleIndex indexPath = (JSONPathSingleIndex) indexPaths[i];
        indexes[i] = indexPath.index;
    }
    this.indexes = indexes;

    boolean duplicate = false;
    int maxIndex = -1;
    for (int i = 0; i < indexes.length; i++) {
        int index = indexes[i];
        if (i == 0) {
            maxIndex = index;
        } else {
            maxIndex = Math.max(maxIndex, index);
        }

        for (int j = 0; j < indexes.length && !duplicate; j++) {
            if (j != i && index == indexes[j]) {
                duplicate = true;
                break;
            }
        }
    }
    this.duplicate = duplicate;
    this.maxIndex = maxIndex;
}

public final boolean isWriteTypeInfo(Object object, Type fieldType) {
    long features = context.features;
    if ((features & WriteClassName.mask) == 0
            || object == null
    ) {
        return false;
    }

    Class objectClass = object.getClass();
    Class fieldClass = null;
    if (fieldType instanceof Class) {
        fieldClass = (Class) fieldType;
    } else if (fieldType instanceof GenericArrayType) {
        if (isWriteTypeInfoGenericArray((GenericArrayType) fieldType, objectClass)) {
            return false;
        }
    } else if (fieldType instanceof ParameterizedType) {
        Type rawType = ((ParameterizedType) fieldType).getRawType();
        if (rawType instanceof Class) {
            fieldClass = (Class) rawType;
        }
    }
    if (objectClass == fieldClass) {
        return false;
    }

    if ((features & NotWriteHashMapArrayListClassName.mask) != 0) {
        if (objectClass == HashMap.class || objectClass == ArrayList.class) {
            return false;
        }
    }

    return (features & NotWriteRootClassName.mask) == 0
            || object != this.rootObject;
}

public final boolean isWriteTypeInfo(Object object, Type fieldType, long features) {
    features |= context.features;

    if ((features & WriteClassName.mask) == 0) {
        return false;
    }

    if (object == null) {
        return false;
    }

    Class objectClass = object.getClass();
    Class fieldClass = null;
    if (fieldType instanceof Class) {
        fieldClass = (Class) fieldType;
    } else if (fieldType instanceof ParameterizedType) {
        Type rawType = ((ParameterizedType) fieldType).getRawType();
        if (rawType instanceof Class) {
            fieldClass = (Class) rawType;
        }
    }
    if (objectClass == fieldClass) {
        return false;
    }

    if ((features & NotWriteHashMapArrayListClassName.mask) != 0) {
        if (objectClass == HashMap.class) {
            if (fieldClass == null || fieldClass == Object.class || fieldClass == Map.class || fieldClass == AbstractMap.class) {
                return false;
            }
        } else if (objectClass == ArrayList.class) {
            return false;
        }
    }

    return (features & NotWriteRootClassName.mask) == 0
            || object != this.rootObject;
}

public void writeString(List<String> list) {
    if (list == null) {
        writeArrayNull();
        return;
    }

    final int size = list.size();
    startArray(size);

    if (STRING_VALUE != null && STRING_CODER != null) {
        int off = this.off;
        byte[] bytes = this.bytes;
        final int LATIN = 0;
        boolean latinAll = true;
        for (int i = 0; i < size; i++) {
            String str = list.get(i);
            if (str == null) {
                if (off == bytes.length) {
                    bytes = grow(off + 1);
                }
                bytes[off++] = BC_NULL;
                continue;
            }
            int coder = STRING_CODER.applyAsInt(str);
            if (coder != LATIN) {
                latinAll = false;
                break;
            }
            byte[] value = STRING_VALUE.apply(str);
            if (off + value.length + 6 >= bytes.length) {
                bytes = grow(off + value.length + 6);
            }
            off = JSONB.IO.writeStringLatin1(bytes, off, value);
        }
        if (latinAll) {
            this.off = off;
            return;
        }
    }

    for (int i = 0; i < size; i++) {
        writeString(
                list.get(i)
        );
    }
}

@Override
    public void writeZonedDateTime(ZonedDateTime dateTime) {
        if (dateTime == null) {
            writeNull();
            return;
        }

        int off = this.off;
        byte[] bytes = this.bytes;
        if (off + 13 > bytes.length) {
            bytes = grow(off + 13);
        }

        putIntBE(bytes,
                off,
                (BC_TIMESTAMP_WITH_TIMEZONE << 24) | (dateTime.getYear() << 8) | dateTime.getMonthValue());
        putIntBE(bytes,
                off + 4,
                (dateTime.getDayOfMonth() << 24)
                        | (dateTime.getHour() << 16)
                        | (dateTime.getMinute() << 8)
                        | dateTime.getSecond());
        this.off = JSONB.IO.writeInt32(bytes, off + 8, dateTime.getNano());

        String zoneIdStr = dateTime.getZone().getId();
        if (zoneIdStr.equals(SHANGHAI_ZONE_ID_NAME)) {
            writeRaw(SHANGHAI_ZONE_ID_NAME_BYTES);
        } else {
            writeString(zoneIdStr);
        }
    }

final void writeStringBrowserSecure(char[] value) {
    boolean escapeNoneAscii = (context.features & EscapeNoneAscii.mask) != 0;

    boolean escape = false;
    int off = this.off;
    int minCapacity = off + value.length + 2;
    if (minCapacity >= chars.length) {
        grow(minCapacity);
    }

    final char[] chars = this.chars;
    chars[off++] = quote;
    for (int i = 0, char_len = value.length; i < char_len; i++) {
        char c = getChar(value, i);
        if (c == '\\'
                || c == quote
                || c < ' '
                || c == '<'
                || c == '>'
                || c == '('
                || c == ')'
                || (escapeNoneAscii && c > 0x007F)
        ) {
            escape = true;
            break;
        }

        chars[off++] = c;
    }

    if (!escape) {
        chars[off] = quote;
        this.off = off + 1;
        return;
    }

    writeStringEscape(value);
}

@Override
    public final void writeBigInt(BigInteger value, long features) {
        if (value == null) {
            writeNumberNull(features);
            return;
        }

        if (isInt64(value) && features == 0) {
            writeInt64(value.longValue());
            return;
        }

        String str = value.toString(10);

        boolean writeAsString = isWriteAsString(value, context.features | features);

        int off = this.off;
        int strlen = str.length();

        int minCapacity = off + strlen + (writeAsString ? 2 : 0);
        char[] chars = this.chars;
        if (minCapacity > this.chars.length) {
            chars = grow(minCapacity);
        }

        if (writeAsString) {
            chars[off++] = '"';
        }
        str.getChars(0, strlen, chars, off);
        off += strlen;
        if (writeAsString) {
            chars[off++] = '"';
        }
        this.off = off;
    }

@Override
    public final void writeFloat(float[] values) {
        if (values == null) {
            writeArrayNull();
            return;
        }

        boolean writeAsString = (context.features & WriteNonStringValueAsString.mask) != 0;
        boolean writeSpecialAsString = (context.features & WriteFloatSpecialAsString.mask) != 0;

        int off = this.off;
        int minCapacity = off + values.length * 18 + 2;
        char[] chars = this.chars;
        if (minCapacity > chars.length) {
            chars = grow(minCapacity);
        }

        chars[off++] = '[';
        for (int i = 0; i < values.length; i++) {
            if (i != 0) {
                chars[off++] = ',';
            }

            if (!Float.isFinite(values[i])) {
                off = NumberUtils.writeFloat(chars, off, values[i], true, writeSpecialAsString);
            } else {
                if (writeAsString) {
                    chars[off++] = '"';
                }
                off = NumberUtils.writeFloat(chars, off, values[i], true, false);
                if (writeAsString) {
                    chars[off++] = '"';
                }
            }
        }
        chars[off] = ']';
        this.off = off + 1;
    }

